{
"@context":"http://schema.org",
"@type":"FAQPage",
"mainEntity":[
{"@type":"Question","name":"What is the difference between SEO, AEO, and GEO?","acceptedAnswer":{"@type":"Answer","text":"SEO focuses on traditional search engines like Google. AEO optimizes for featured snippets and voice search. GEO structures content for AI platforms like ChatGPT and Gemini."}},
{"@type":"Question","name":"How long does it take to see SEO results?","acceptedAnswer":{"@type":"Answer","text":"Most clients see measurable improvements within 3-6 months. Technical fixes show impact in 4-8 weeks."}},
{"@type":"Question","name":"Do you work with US and UK businesses only?","acceptedAnswer":{"@type":"Answer","text":"Our core expertise is US and UK markets, but we work with businesses globally."}},
{"@type":"Question","name":"What platforms do you optimize for AI search?","acceptedAnswer":{"@type":"Answer","text":"ChatGPT, Google Gemini, Perplexity, Bing Chat, Claude, and emerging AI search platforms."}},
{"@type":"Question","name":"Do you offer standalone SEO audits?","acceptedAnswer":{"@type":"Answer","text":"Yes. Comprehensive SEO audit covering technical SEO, on-page analysis, content audit, backlink profile, and competitor benchmarks."}}
]}

body.script:
//
// Mobile Menu
function openMobile() {
document.getElementById('mobileOverlay').classList.add('open');
document.getElementById('mobilePanel').classList.add('open');
}
function closeMobile() {
document.getElementById('mobileOverlay').classList.remove('open');
document.getElementById('mobilePanel').classList.remove('open');
}
// Search
function openSearch() {
document.getElementById('searchOverlay').classList.add('open');
document.getElementById('searchOverlay').querySelector('input').focus();
}
function closeSearch() {
document.getElementById('searchOverlay').classList.remove('open');
}
// Dark Mode
function toggleDark() {
document.body.classList.toggle('dark-mode');
var isDark = document.body.classList.contains('dark-mode');
localStorage.setItem('rankrseo-dark', isDark ? 'true' : 'false');
var btn = document.getElementById('darkToggle');
btn.innerHTML = isDark ? '&#9728;' : '&#9790;';
}
if (localStorage.getItem('rankrseo-dark') === 'true') {
document.body.classList.add('dark-mode');
document.getElementById('darkToggle').innerHTML = '&#9728;';
}
// FAQ Accordion
function toggleFaq(btn) {
var item = btn.parentElement;
item.classList.toggle('open');
}
// Current Year in Footer
document.querySelectorAll('.footer-copyright .widget-content p').forEach(function(el) {
el.innerHTML = el.innerHTML.replace('2025', new Date().getFullYear());
});
//
